    /**
     * Provenance ID
     * @type {string}
     * @memberof OmopDbMeasurementForUpload
     */
    'provenance_id'?: string | null;
    /**
     * Source traceback
     * @type {string}
     * @memberof OmopDbMeasurementForUpload
     */
    'source_traceback'?: string | null;
    /**
     * The UTC datetime when the object was created.
     * @type {string}
     * @memberof OmopDbMeasurementForUpload
     */
    'created_at'?: string | null;
    /**
     * The UTC datetime when the object was last modified.
     * @type {string}
     * @memberof OmopDbMeasurementForUpload
     */
    'modified_at'?: string | null;
    /**
     * The ID of the user who last modified the object.
     * @type {string}
     * @memberof OmopDbMeasurementForUpload
     */
    'modified_by'?: string | null;
    /**
     * The id of the measurement.
     * @type {string}
     * @memberof OmopDbMeasurementForUpload
     */
    'measurement_id'?: string;
    /**
     * The id of the person associated with the measurement. If not available, it must be filled with the null ID.
     * @type {string}
     * @memberof OmopDbMeasurementForUpload
     */
